        td {
            padding: 15px;
            border-bottom: 1px solid rgba(255,255,255,0.1);
        }

        tr:hover {
            background: rgba(255,255,255,0.03);
        }

        /* 代码块 */
        code {
            background: rgba(255,255,255,0.1);
            padding: 2px 8px;
            border-radius: 4px;
            font-family: 'Share Tech Mono', monospace;
            font-size: 0.9em;
            color: var(--neon-cyan);
        }

        pre {
            background: rgba(0,0,0,0.5);
            padding: 20px;
            border-radius: 10px;
            overflow-x: auto;
            border: 1px solid rgba(255,255,255,0.1);
            margin: 20px 0;
        }

        pre code {
            background: none;
            padding: 0;
        }

        /* 图示容器 */
        .diagram {
            background: rgba(0,0,0,0.3);
            border: 1px solid rgba(255,255,255,0.1);
            border-radius: 15px;
            padding: 30px;
            margin: 30px 0;
            text-align: center;
        }

        .diagram-title {
            color: var(--neon-gold);
            font-weight: 600;
            margin-bottom: 20px;
        }

        /* 交互流程图 */
        .flow {
            display: flex;
            flex-wrap: wrap;
            justify-content: center;
            align-items: center;
            gap: 15px;
            margin: 30px 0;
        }

        .flow-step {
            background: linear-gradient(135deg, var(--section-blue), var(--deep-blue));
            padding: 15px 25px;
            border-radius: 30px;
            border: 1px solid var(--neon-cyan);
            color: var(--neon-cyan);
            font-weight: 500;
        }

        .flow-arrow {
            color: var(--neon-gold);
            font-size: 1.5rem;
        }

        /* 双音特性展示 */
        .dual-tone-demo {
            display: flex;
            justify-content: center;
            gap: 40px;
            margin: 30px 0;
            flex-wrap: wrap;
        }

        .tone-box {
            background: rgba(0,0,0,0.3);
            border: 2px solid;
            border-radius: 15px;
            padding: 25px 35px;
            text-align: center;
            min-width: 200px;
        }

        .tone-box.zheng {
            border-color: var(--neon-cyan);
        }

        .tone-box.ce {
            border-color: var(--neon-pink);
        }

        .tone-box h4 {
            font-size: 1.3rem;
            margin-bottom: 15px;
        }

        .tone-box.zheng h4 { color: var(--neon-cyan); }
        .tone-box.ce h4 { color: var(--neon-pink); }

        .tone-note {
            font-size: 2rem;
            font-weight: 700;
            margin: 10px 0;
        }

        .tone-freq {
            font-family: 'Share Tech Mono', monospace;
            color: rgba(255,255,255,0.6);
            font-size: 0.9rem;
        }

        /* 音频波形示意 */
        .waveform {
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 3px;
            height: 60px;
            margin: 20px 0;
        }

        .wave-bar {
            width: 4px;
            background: linear-gradient(to top, var(--neon-gold), transparent);
            border-radius: 2px;
            animation: wave 1.2s ease-in-out infinite;
        }

        @keyframes wave {
            0%, 100% { height: 20%; }
            50% { height: 100%; }
        }

        /* 标签 */
        .tag {
            display: inline-block;
            padding: 4px 12px;
            border-radius: 15px;
            font-size: 0.75rem;
            font-weight: 600;
            margin: 3px;
        }

        .tag-tech { background: rgba(0,255,255,0.15); color: var(--neon-cyan); }
        .tag-ui { background: rgba(255,0,255,0.15); color: var(--neon-pink); }
        .tag-core { background: rgba(245,175,25,0.15); color: var(--neon-gold); }
        .tag-complete { background: rgba(57,255,20,0.15); color: var(--neon-green); }

        /* 功能状态 */
        .status {
            display: inline-flex;
            align-items: center;
            gap: 6px;
            font-size: 0.85rem;
        }

        .status-dot {
            width: 8px;
            height: 8px;
            border-radius: 50%;
        }

        .status-complete .status-dot { background: var(--neon-green); box-shadow: 0 0 8px var(--neon-green); }
        .status-complete { color: var(--neon-green); }
        .status-progress .status-dot { background: var(--neon-gold); }
        .status-progress { color: var(--neon-gold); }

        /* 底部 */
        .footer {
            background: var(--deep-blue);
            padding: 40px 20px;
            text-align: center;
            border-top: 2px solid rgba(245, 175, 25, 0.3);
        }

        .footer a {
            color: var(--neon-gold);
            text-decoration: none;
            display: inline-flex;
            align-items: center;
            gap: 10px;
            padding: 15px 30px;
            border: 2px solid var(--neon-gold);
            border-radius: 30px;
            font-weight: 600;
            transition: all 0.3s;
        }

        .footer a:hover {
            background: var(--neon-gold);
            color: var(--dark);
        }

        /* 锚点偏移修正 */
        .anchor {
            display: block;
            position: relative;
            top: -70px;
            visibility: hidden;
        }

        /* 截图容器 */
        .screenshot-container {
            background: rgba(0,0,0,0.3);
            border: 2px solid rgba(245, 175, 25, 0.3);
            border-radius: 15px;
            padding: 20px;
            margin: 25px 0;
            text-align: center;
        }

        .screenshot-container img {
            max-width: 100%;
            border-radius: 10px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
        }

        .screenshot-annotation {
            margin-top: 20px;
            text-align: left;
            background: rgba(0,0,0,0.4);
            padding: 20px;
            border-radius: 10px;
            border-left: 4px solid var(--neon-gold);
        }
        @media (max-width: 768px) {
            .header h1 { font-size: 2rem; }
            .section-title { font-size: 1.5rem; }
            .nav-inner { gap: 5px; }
            .nav a { padding: 6px 10px; font-size: 0.8rem; }
            table { font-size: 0.85rem; }
            th, td { padding: 10px; }
        }
    </style>
</head>
